    "category": "Operational Playbook",
    "content": "\"use client\"; type ChecklistType = \"landing-page\" | \"email\" | \"sms\" | \"workflow\" | \"go-live\" | \"handoff\"; const checklists: Record = \"landing-page\": title: \"Landing Page Checklist\", description: \"Quality assurance for landing pages and funnels (Week 2 deliverables)\", sections: [ title: \"Design & Layout\", items: [ \"Page loads correctly on desktop\", \"Page loads correctly on mobile (responsive)\", \"Page loads correctly on tablet\", \"All images display properly and are optimized\", \"Brand colors match client brand guidelines\", \"Logo is properly sized and positioned\", \"Typography is consistent throughout\", \"Proper spacing and whitespace\", \"Visual hierarchy is clear (headline → subhead → body → CTA)\" ] , title: \"Content & Copy\", items: [ \"Headline is clear and compelling\", \"Subheadline supports the main message\", \"Body copy is error-free (spelling, grammar)\", \"Benefits are clearly communicated\", \"Social proof/testimonials are included (if applicable)\", \"Call-to-action is clear and prominent\", \"All placeholder text has been replaced\" ] , title: \"Forms & Functionality\", items: [ \"Form fields are correctly labeled\", \"Form validation works (required fields)\", \"Form submission works correctly\", \"Form data maps to correct GHL fields\", \"Success/thank you message displays after submission\", \"Redirect to thank you page works (if applicable)\", \"All buttons and links work\" ] , title: \"Technical & SEO\", items: [ \"Page title is set correctly\", \"Meta description is set\", \"Favicon displays correctly\", \"Page URL is clean and descriptive\", \"SSL certificate is active (https)\", \"Page load speed is acceptable ( checklists[key]; return key: key, label: checklist.title.replace(\" Checklist\", \"\"), title: checklist.title, description: checklist.description, content: ( checklist.sections.map((section) => ( section.title section.items.map((item) => ( item )) )) ), footer: ( Total Items: checklist.sections.reduce((acc, s) => acc + s.items.length, 0) Sign-off: _________________ Date: _________________ ) ; ); return ( Operations Playbook Quality Checklists Ensure every deliverable meets Carisle Media quality standards before client delivery. /* Checklist Purpose */ How to Use Select the appropriate checklist for the deliverable type Complete all items before marking deliverable as &quot;ready for review&quot; Get sign-off from QA reviewer (Operations Coordinator or Web Developer lead) Attach completed checklist to client delivery Definition of Done: A deliverable is only &quot;done&quot; when all checklist items are marked complete, QA reviewer has signed off, and client has approved (where applicable). /* Reusable FolderTabs Component */ ); return ( ); \"use client\"; interface PlaybookPageLayoutProps children: ReactNode; : PlaybookPageLayoutProps) return ( /* Content */ children /* Footer */ ); \"use client\"; interface Tab key: string; label: string; title: string; description: string; content: ReactNode; interface FolderTabsProps tabs: Tab[]; defaultTab?: string; hashToTabMap?: Record ; // Maps hash IDs to tab keys const EMPTY_HASH_TO_TAB_MAP: Record = ; : FolderTabsProps) const [activeTab, setActiveTab] = useState(defaultTab || tabs[0]?.key); tabs.find(t => t.key === activeTab) || tabs[0]; useRef (null); // Handle hash-based navigation useEffect(() => () => window.location.hash.slice(1); // Remove the # if (!hash) return; // Check if hash maps to a specific tab hashToTabMap[hash]; if (targetTab && tabs.find(t => t.key === targetTab)) setActiveTab(targetTab); // Wait for tab to switch, then scroll to element setTimeout(() => document.getElementById(hash); if (element) element.scrollIntoView( behavior: 'smooth', block: 'start' ); , 100); else // Try to find element directly document.getElementById(hash); if (element) element.scrollIntoView( behavior: 'smooth', block: 'start' ); ; // Check hash on mount handleHashChange(); // Listen for hash changes window.addEventListener('hashchange', handleHashChange); return () => window.removeEventListener('hashchange', handleHashChange); , [hashToTabMap, tabs]); (nextTabKey: string) => setActiveTab(nextTabKey); containerRef.current?.scrollIntoView( behavior: 'smooth', block: 'start' ); ; return ( /* Folder Tabs */ tabs.map((tab) => activeTab === tab.key; return ( setActiveTab(tab.key) className= cn( \"relative h-9 md:h-10 px-3 md:px-5 min-w-[80px] md:min-w-[100px] text-xs md:text-sm font-semibold transition-all duration-200 focus:outline-none rounded-t-lg folder-tab snap-start shrink-0 whitespace-nowrap\", isActive ? \"z-30 text-white bg-primary folder-tab-active\" : \"text-foreground hover:opacity-80 z-10 folder-tab-inactive\" ) style= backgroundColor: isActive ? 'hsl(192 60% 25%)' : 'hsl(192 50% 70%)' > tab.label ); ) /* Content Card */ /* Header - with dark teal border */ currentTab.title currentTab.description /* Content - with light teal border */ currentTab.content /* Tab Navigation */ (() => tabs.findIndex(t => t.key === activeTab); tabs[currentIndex - 1]; tabs[currentIndex + 1]; if (!prevTab && !nextTab) return null; return ( /* Previous Button */ prevTab ? ( handleNextTab(prevTab.key) > prevTab.label ) : ( ) /* Next Button */ nextTab && ( handleNextTab(nextTab.key) > nextTab.label ) ); )() ); qa testing standards review audit compliance checklist quality assurance quality control verify validation check task list todo"
